<?php
 namespace WPAICG\AutoGPT\Cron\EventProcessor\Trigger\Modules; if (!defined('ABSPATH')) { exit; } function parse_schedule_datetime_logic(string $raw): array { $raw_original = trim($raw); if ($raw_original === '') { return ['gmt' => null, 'error' => 'empty']; } $raw_clean = preg_replace('/\s+/', ' ', $raw_original); $candidates = []; if (preg_match('/T/', $raw_clean)) { $iso = $raw_clean; $candidates[] = function() use ($iso) { $ts = strtotime($iso); return $ts ? ['ts' => $ts, 'is_utc' => true] : null; }; } $dash_no_sec = '/^(\d{4})-(\d{2})-(\d{2}) (\d{2}):(\d{2})$/'; if (preg_match($dash_no_sec, $raw_clean)) { $candidates[] = function() use ($raw_clean) { $dt = date_create_from_format('Y-m-d H:i', $raw_clean, wp_timezone()); return $dt ? ['ts' => $dt->getTimestamp(), 'is_utc' => false] : null; }; } $dash_with_sec = '/^(\d{4})-(\d{2})-(\d{2}) (\d{2}):(\d{2}):(\d{2})$/'; if (preg_match($dash_with_sec, $raw_clean)) { $candidates[] = function() use ($raw_clean) { $dt = date_create_from_format('Y-m-d H:i:s', $raw_clean, wp_timezone()); return $dt ? ['ts' => $dt->getTimestamp(), 'is_utc' => false] : null; }; } $slash_pattern = '/^(\d{1,2})\/(\d{1,2})\/(\d{4}) (\d{2}):(\d{2})(?::(\d{2}))?$/'; if (preg_match($slash_pattern, $raw_clean, $m)) { $a = (int)$m[1]; $b = (int)$m[2]; $Y = (int)$m[3]; $H = (int)$m[4]; $i = (int)$m[5]; $s = isset($m[6]) ? (int)$m[6] : 0; $is_day_first = $a > 12; $day = $is_day_first ? $a : $b; $mon = $is_day_first ? $b : $a; if (checkdate($mon, $day, $Y)) { $candidates[] = function() use ($Y,$mon,$day,$H,$i,$s) { $dt = new \DateTime(sprintf('%04d-%02d-%02d %02d:%02d:%02d', $Y,$mon,$day,$H,$i,$s), wp_timezone()); return ['ts' => $dt->getTimestamp(), 'is_utc' => false]; }; } } $candidates[] = function() use ($raw_clean) { $ts = strtotime($raw_clean); return $ts ? ['ts' => $ts, 'is_utc' => false] : null; }; foreach ($candidates as $resolver) { $res = $resolver(); if ($res && !empty($res['ts'])) { $utc_ts = $res['is_utc'] ? $res['ts'] : $res['ts'] - (int) get_option('gmt_offset') * HOUR_IN_SECONDS; return ['gmt' => gmdate('Y-m-d H:i:s', $utc_ts), 'error' => null]; } } return ['gmt' => null, 'error' => 'unparsed']; } function parse_schedule_datetime_simple_logic(string $raw): ?string { $res = parse_schedule_datetime_logic($raw); return $res['gmt']; } function compute_item_schedule_gmt_logic($item_data, array $task_config, int $item_index, string $generation_mode): ?string { $schedule_mode = $task_config['schedule_mode'] ?? 'immediate'; $scheduled_gmt_time = null; if ($schedule_mode === 'from_input') { $date_str = ''; if ($generation_mode === 'gsheets' && is_array($item_data) && !empty($item_data['schedule_date'])) { $date_str = $item_data['schedule_date']; } elseif (is_array($item_data) && !empty($item_data['schedule_date'])) { $date_str = $item_data['schedule_date']; } else { $raw = is_array($item_data) ? ($item_data['topic'] ?? '') : $item_data; if (is_string($raw) && strpos($raw, '|') !== false) { $parts = array_map('trim', explode('|', $raw)); if (count($parts) > 1) { $date_str_candidate = end($parts); if (preg_match('/\d/', $date_str_candidate)) { $date_str = $date_str_candidate; } } } } if ($date_str !== '') { $parsed = parse_schedule_datetime_simple_logic($date_str); if ($parsed) { $scheduled_gmt_time = $parsed; } } } elseif ($schedule_mode === 'smart' && !empty($task_config['smart_schedule_start_datetime'])) { try { $start_local = new \DateTime($task_config['smart_schedule_start_datetime'], wp_timezone()); $interval_value = absint($task_config['smart_schedule_interval_value'] ?? 1); $interval_unit = $task_config['smart_schedule_interval_unit'] ?? 'hours'; $offset_value = $item_index * $interval_value; $start_local->modify("+{$offset_value} {$interval_unit}"); $local_str = $start_local->format('Y-m-d H:i:s'); $scheduled_gmt_time = get_gmt_from_date($local_str, 'Y-m-d H:i:s'); } catch (\Exception $e) { $scheduled_gmt_time = null; } } return $scheduled_gmt_time; } 